CREATE TABLE `wp_webinar_certificates` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `certificate_id` varchar(50) NOT NULL,
  `event_id` bigint(20) unsigned NOT NULL,
  `period_id` bigint(20) unsigned NOT NULL,
  `student_user_id` bigint(20) unsigned NOT NULL,
  `student_email` varchar(190) NOT NULL,
  `student_name` varchar(190) NOT NULL,
  `webinar_title` varchar(500) NOT NULL,
  `completion_date` datetime NOT NULL,
  `duration_minutes` int(10) unsigned NOT NULL,
  `instructor_name` varchar(190) DEFAULT NULL,
  `html_content` longtext NOT NULL,
  `status` varchar(20) NOT NULL DEFAULT 'active',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_cert` (`certificate_id`),
  UNIQUE KEY `uniq_student_event` (`student_user_id`,`event_id`,`period_id`),
  KEY `student` (`student_user_id`),
  KEY `event` (`event_id`),
  KEY `status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;
INSERT INTO `wp_webinar_certificates` (`id`,`certificate_id`,`event_id`,`period_id`,`student_user_id`,`student_email`,`student_name`,`webinar_title`,`completion_date`,`duration_minutes`,`instructor_name`,`html_content`,`status`,`created_at`,`updated_at`) VALUES('1','WEB-2025-000001','8','8','237520670','9923103294@mail.jiit.ac.in','Sanyam Jain','Cardio','2025-12-31 11:00:00','120',NULL,'<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<title>Certificate of Completion</title>\n\n<style>\n*{box-sizing:border-box;margin:0;padding:0}\n\nbody{\n    font-family:\'Playfair Display\',Georgia,serif;\n    background:#ffffff;\n    color:#1a1a2e;\n    font-size:14px;\n    line-height:1.6;\n}\n\n/* ===== CERTIFICATE CONTAINER ===== */\n.cert-container{\n    max-width:1000px;\n    margin:40px auto;\n    padding:0 20px;\n}\n\n.cert-card{\n    background:#ffffff;\n    border:12px solid #0f172a;\n    border-radius:8px;\n    padding:60px 80px;\n    position:relative;\n    box-shadow:0 20px 60px rgba(0,0,0,0.15);\n}\n\n/* Decorative corner elements */\n.cert-card::before,\n.cert-card::after{\n    content:\'\';\n    position:absolute;\n    width:80px;\n    height:80px;\n    border:3px solid #6c47ff;\n}\n\n.cert-card::before{\n    top:30px;\n    left:30px;\n    border-right:none;\n    border-bottom:none;\n}\n\n.cert-card::after{\n    bottom:30px;\n    right:30px;\n    border-left:none;\n    border-top:none;\n}\n\n/* ===== HEADER ===== */\n.cert-header{\n    text-align:center;\n    margin-bottom:40px;\n    padding-bottom:30px;\n    border-bottom:2px solid #e5e7eb;\n}\n\n.cert-logo{\n    display:inline-flex;\n    align-items:center;\n    gap:12px;\n    margin-bottom:20px;\n}\n\n.cert-logo svg{\n    width:50px;\n    height:50px;\n}\n\n.cert-logo-text{\n    font-size:32px;\n    font-weight:900;\n    color:#6c47ff;\n    font-family:\'Inter\',sans-serif;\n    letter-spacing:-1px;\n}\n\n.cert-header h1{\n    font-size:48px;\n    font-weight:700;\n    color:#0f172a;\n    margin-bottom:8px;\n    letter-spacing:2px;\n    text-transform:uppercase;\n}\n\n.cert-header .subtitle{\n    font-size:18px;\n    color:#64748b;\n    font-style:italic;\n    font-family:\'Inter\',sans-serif;\n}\n\n/* ===== BODY ===== */\n.cert-body{\n    text-align:center;\n    margin:50px 0;\n}\n\n.cert-presented{\n    font-size:20px;\n    color:#64748b;\n    margin-bottom:20px;\n    font-family:\'Inter\',sans-serif;\n}\n\n.cert-name{\n    font-size:56px;\n    font-weight:700;\n    color:#1a1a2e;\n    margin:20px 0;\n    padding:0 40px;\n    border-bottom:3px solid #6c47ff;\n    display:inline-block;\n    letter-spacing:1px;\n}\n\n.cert-completion{\n    font-size:18px;\n    color:#475569;\n    margin:30px auto;\n    max-width:700px;\n    line-height:1.8;\n    font-family:\'Inter\',sans-serif;\n}\n\n.cert-webinar-title{\n    font-size:32px;\n    font-weight:600;\n    color:#6c47ff;\n    margin:25px 0;\n    font-style:italic;\n}\n\n/* ===== DETAILS SECTION ===== */\n.cert-details{\n    display:grid;\n    grid-template-columns:1fr 1fr;\n    gap:30px;\n    margin:50px 0;\n    padding:40px;\n    background:#f8f9fa;\n    border-radius:8px;\n    border:1px solid #e5e7eb;\n}\n\n.cert-detail-item{\n    text-align:left;\n}\n\n.cert-detail-label{\n    font-size:13px;\n    color:#64748b;\n    text-transform:uppercase;\n    letter-spacing:1px;\n    margin-bottom:8px;\n    font-family:\'Inter\',sans-serif;\n    font-weight:600;\n}\n\n.cert-detail-value{\n    font-size:18px;\n    color:#1a1a2e;\n    font-weight:500;\n    font-family:\'Inter\',sans-serif;\n}\n\n/* ===== SIGNATURES ===== */\n.cert-signatures{\n    display:flex;\n    justify-content:space-around;\n    margin-top:60px;\n    padding-top:40px;\n    border-top:2px solid #e5e7eb;\n}\n\n.cert-signature{\n    text-align:center;\n    flex:1;\n}\n\n.cert-sig-line{\n    width:200px;\n    height:60px;\n    border-bottom:2px solid #1a1a2e;\n    margin:0 auto 10px;\n    display:flex;\n    align-items:flex-end;\n    justify-content:center;\n}\n\n.cert-sig-image{\n    max-width:180px;\n    max-height:50px;\n    object-fit:contain;\n    margin-bottom:5px;\n}\n\n.cert-sig-name{\n    font-size:16px;\n    font-weight:700;\n    color:#1a1a2e;\n    margin-bottom:4px;\n    font-family:\'Inter\',sans-serif;\n}\n\n.cert-sig-title{\n    font-size:13px;\n    color:#64748b;\n    font-style:italic;\n    font-family:\'Inter\',sans-serif;\n}\n\n/* ===== FOOTER ===== */\n.cert-footer{\n    text-align:center;\n    margin-top:50px;\n    padding-top:30px;\n    border-top:2px solid #e5e7eb;\n}\n\n.cert-id{\n    font-size:12px;\n    color:#94a3b8;\n    margin-bottom:15px;\n    font-family:\'Courier New\',monospace;\n    letter-spacing:1px;\n}\n\n.cert-verify{\n    font-size:13px;\n    color:#64748b;\n    font-family:\'Inter\',sans-serif;\n}\n\n.cert-verify a{\n    color:#6c47ff;\n    text-decoration:none;\n    font-weight:600;\n}\n\n.cert-verify a:hover{\n    text-decoration:underline;\n}\n\n.cert-company-info{\n    margin-top:20px;\n    font-size:12px;\n    color:#94a3b8;\n    font-family:\'Inter\',sans-serif;\n}\n\n/* ===== SEAL ===== */\n.cert-seal{\n    position:absolute;\n    bottom:80px;\n    right:80px;\n    width:120px;\n    height:120px;\n}\n\n.cert-seal-circle{\n    width:100%;\n    height:100%;\n    border-radius:50%;\n    border:4px solid #6c47ff;\n    display:flex;\n    flex-direction:column;\n    align-items:center;\n    justify-content:center;\n    background:#ffffff;\n    box-shadow:0 4px 12px rgba(108,71,255,0.2);\n}\n\n.cert-seal-year{\n    font-size:28px;\n    font-weight:900;\n    color:#6c47ff;\n    font-family:\'Inter\',sans-serif;\n}\n\n.cert-seal-text{\n    font-size:10px;\n    color:#64748b;\n    text-transform:uppercase;\n    letter-spacing:1px;\n    font-family:\'Inter\',sans-serif;\n    font-weight:600;\n}\n\n/* ===== ACTIONS ===== */\n.cert-actions{\n    margin-top:40px;\n    text-align:center;\n}\n\n.cert-btn{\n    display:inline-flex;\n    align-items:center;\n    gap:8px;\n    padding:12px 28px;\n    background:#6c47ff;\n    color:#ffffff;\n    border:none;\n    border-radius:6px;\n    font-size:15px;\n    font-weight:600;\n    font-family:\'Inter\',sans-serif;\n    cursor:pointer;\n    text-decoration:none;\n    transition:background 0.2s,transform 0.1s;\n}\n\n.cert-btn:hover{\n    background:#5535e0;\n    transform:translateY(-1px);\n}\n\n.cert-btn svg{\n    width:18px;\n    height:18px;\n}\n\n/* ===== PRINT STYLES ===== */\n@media print{\n    @page{\n        size:landscape;\n        margin:0.5in;\n    }\n    \n    body{\n        background:#fff;\n    }\n    \n    .cert-container{\n        margin:0;\n        padding:0;\n    }\n    \n    .cert-card{\n        box-shadow:none;\n        page-break-inside:avoid;\n    }\n    \n    .cert-actions{\n        display:none;\n    }\n}\n\n/* ===== RESPONSIVE ===== */\n@media(max-width:768px){\n    .cert-card{\n        padding:40px 30px;\n        border-width:8px;\n    }\n    \n    .cert-card::before,\n    .cert-card::after{\n        width:50px;\n        height:50px;\n    }\n    \n    .cert-card::before{\n        top:20px;\n        left:20px;\n    }\n    \n    .cert-card::after{\n        bottom:20px;\n        right:20px;\n    }\n    \n    .cert-header h1{\n        font-size:32px;\n    }\n    \n    .cert-name{\n        font-size:36px;\n        padding:0 20px;\n    }\n    \n    .cert-webinar-title{\n        font-size:24px;\n    }\n    \n    .cert-details{\n        grid-template-columns:1fr;\n        gap:20px;\n        padding:30px 20px;\n    }\n    \n    .cert-seal{\n        position:static;\n        margin:30px auto 0;\n    }\n}\n</style>\n\n<!-- Google Fonts -->\n<link href=\"https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;600;700&family=Inter:wght@400;500;600;700;900&display=swap\" rel=\"stylesheet\">\n\n</head>\n<body>\n\n<div class=\"cert-container\">\n    <div class=\"cert-card\">\n    \n        <!-- Header -->\n        <div class=\"cert-header\">\n            <div class=\"cert-logo\">\n                <svg viewBox=\"0 0 50 50\" fill=\"none\">\n                    <rect width=\"50\" height=\"50\" rx=\"12\" fill=\"#6c47ff\"/>\n                    <path d=\"M15 18l10-5 10 5v14l-10 5-10-5V18z\" stroke=\"#fff\" stroke-width=\"2\" fill=\"none\"/>\n                    <path d=\"M25 13v24M15 18l10 10 10-10\" stroke=\"#fff\" stroke-width=\"2\" stroke-linecap=\"round\"/>\n                </svg>\n                <span class=\"cert-logo-text\"></span>\n            </div>\n            <h1>Certificate of Completion</h1>\n            <div class=\"subtitle\">This certifies that</div>\n        </div>\n        \n        <!-- Body -->\n        <div class=\"cert-body\">\n            <div class=\"cert-presented\">This is proudly presented to</div>\n            \n            <div class=\"cert-name\">Sanyam Jain</div>\n            \n            <div class=\"cert-completion\">\n                for successfully completing the webinar\n            </div>\n            \n            <div class=\"cert-webinar-title\">\"Cardio\"</div>\n            \n            <div class=\"cert-completion\">\n                demonstrating commitment to professional development and continuous learning.\n            </div>\n        </div>\n        \n        <!-- Details -->\n        <div class=\"cert-details\">\n            <div class=\"cert-detail-item\">\n                <div class=\"cert-detail-label\">Date of Completion</div>\n                <div class=\"cert-detail-value\">December 31, 2025</div>\n            </div>\n            \n            <div class=\"cert-detail-item\">\n                <div class=\"cert-detail-label\">Duration</div>\n                <div class=\"cert-detail-value\">2 hours</div>\n            </div>\n            \n            <div class=\"cert-detail-item\">\n                <div class=\"cert-detail-label\">Webinar ID</div>\n                <div class=\"cert-detail-value\">WBN-000008</div>\n            </div>\n            \n            <div class=\"cert-detail-item\">\n                <div class=\"cert-detail-label\">Certificate ID</div>\n                <div class=\"cert-detail-value\">WEB-2025-000001</div>\n            </div>\n        </div>\n        \n        <!-- Signatures -->\n        <div class=\"cert-signatures\">\n            <div class=\"cert-signature\">\n                <div class=\"cert-sig-line\">\n                    <!-- Signature image can be placed here -->\n                </div>\n                <div class=\"cert-sig-name\">Program Instructor</div>\n                <div class=\"cert-sig-title\">Webinar Instructor</div>\n            </div>\n            \n            <div class=\"cert-signature\">\n                <div class=\"cert-sig-line\">\n                    <!-- Signature image can be placed here -->\n                </div>\n                <div class=\"cert-sig-name\">Program Director</div>\n                <div class=\"cert-sig-title\">Program Director</div>\n            </div>\n        </div>\n        \n        <!-- Seal -->\n        <div class=\"cert-seal\">\n            <div class=\"cert-seal-circle\">\n                <div class=\"cert-seal-year\">2025</div>\n                <div class=\"cert-seal-text\">Verified</div>\n            </div>\n        </div>\n        \n        <!-- Footer -->\n        <div class=\"cert-footer\">\n            <div class=\"cert-id\">Certificate ID: WEB-2025-000001</div>\n            <div class=\"cert-verify\">\n                Verify this certificate at \n                <a href=\"https://staging-68a5-inditechsites.wpcomstaging.com/certificate/webinar/WEB-2025-000001\" target=\"_blank\">https://staging-68a5-inditechsites.wpcomstaging.com/certificate/webinar/WEB-2025-000001</a>\n            </div>\n            <div class=\"cert-company-info\">\n                <br>\n                Issued on March 9, 2026\n            </div>\n        </div>\n        \n    </div>\n    \n    <!-- Actions -->\n    <div class=\"cert-actions\">\n        <button class=\"cert-btn\" onclick=\"window.print()\">\n            <svg fill=\"none\" viewBox=\"0 0 24 24\" stroke=\"currentColor\" stroke-width=\"2\">\n                <path d=\"M17 17h2a2 2 0 0 0 2-2v-4a2 2 0 0 0-2-2H5a2 2 0 0 0-2 2v4a2 2 0 0 0 2 2h2\"/>\n                <path d=\"M9 9V5a2 2 0 0 1 2-2h2a2 2 0 0 1 2 2v4\"/>\n                <rect x=\"7\" y=\"13\" width=\"10\" height=\"8\" rx=\"2\"/>\n            </svg>\n            Download Certificate\n        </button>\n    </div>\n</div>\n\n<script>\n// Hide actions before print, show after\nwindow.onbeforeprint = function() {\n    document.querySelector(\'.cert-actions\').style.display = \'none\';\n};\n\nwindow.onafterprint = function() {\n    document.querySelector(\'.cert-actions\').style.display = \'block\';\n};\n</script>\n\n</body>\n</html>','active','2026-03-09 22:08:39','2026-03-09 22:08:39');
