-box{\n    border:1px solid #e5e7eb;\n    border-radius:8px;\n    padding:10px 12px;\n    display:flex;\n    justify-content:space-between;\n    align-items:center;\n    font-size:11px;\n    color:#475569;\n}\n\n.verify-box a{\n    color:#0f172a;\n    font-weight:600;\n    text-decoration:none;\n    font-size:11px;\n}\n\n.verify-box a:hover{\n    text-decoration:underline;\n}\n\n/* ===== ACTIONS ===== */\n.actions{\n    margin-top:16px;\n    display:flex;\n    justify-content:flex-end;\n    gap:10px;\n}\n\n.actions button{\n    padding:8px 14px;\n    border-radius:6px;\n    font-size:12px;\n    cursor:pointer;\n}\n\n.download{\n    background:#0f172a;\n    color:#ffffff;\n    border:none;\n}\n\n/* ===== FOOTER ===== */\n.footer{\n    margin-top:20px;\n    padding:12px 0;\n    text-align:center;\n    font-size:10px;\n    color:#64748b;\n    border-top:1px solid #e5e7eb;\n    background:#ffffff;\n}\n.footer p{margin:2px 0}\n\n/* ===== PRINT STYLES ===== */\n@media print{\n    @page{\n        margin:0.5in;\n    }\n    body{\n        background:#fff;\n        font-size:11px;\n    }\n    .page{\n        margin:0;\n        padding:0;\n    }\n    .card{\n        border:none;\n        padding:0;\n    }\n    .header-inner{\n        padding:8px 0;\n    }\n    h1{font-size:16px}\n    .subtitle{font-size:10px;margin-bottom:12px}\n    .section{margin-bottom:12px}\n    .section h3{font-size:12px;margin-bottom:6px}\n    .info-group{gap:6px 20px}\n    .info-row span{font-size:9px}\n    .info-row strong{font-size:11px}\n    .verify-box{padding:8px 10px}\n    .footer{\n        margin-top:16px;\n        padding:8px 0;\n        font-size:9px;\n    }\n    .actions{display:none}\n}\n</style>\n</head>\n\n<body>\n\n<!-- HEADER -->\n<div class=\"header\">\n    <div class=\"header-inner\">\n        <div class=\"logo\"></div>\n    </div>\n</div>\n\n<div class=\"page\">\n\n    <div class=\"card\">\n\n        <h1>Certificate of Completion</h1>\n        <div class=\"subtitle\">\n            Certificate #WEB-2026-000003 &mdash; Issued to Sanyam Jain upon successful completion of a webinar.\n        </div>\n\n        <!-- Recipient -->\n        <div class=\"section\">\n            <h3>Recipient Details</h3>\n            <div class=\"info-group\">\n                <div class=\"info-row\">\n                    <span>Name</span>\n                    <strong>Sanyam Jain</strong>\n                </div>\n                <div class=\"info-row\">\n                    <span>Email</span>\n                    <strong>{{STUDENT_EMAIL}}</strong>\n                </div>\n            </div>\n        </div>\n\n        <!-- Webinar -->\n        <div class=\"section\">\n            <h3>Webinar Details</h3>\n            <div class=\"info-group\">\n                <div class=\"info-row\">\n                    <span>Webinar Title</span>\n                    <strong>Test Consultation 3</strong>\n                </div>\n                <div class=\"info-row\">\n                    <span>Instructor</span>\n                    <strong>Program Instructor</strong>\n                </div>\n                <div class=\"info-row\">\n                    <span>Date of Completion</span>\n                    <strong>March 17, 2026</strong>\n                </div>\n                <div class=\"info-row\">\n                    <span>Duration</span>\n                    <strong>1 hour</strong>\n                </div>\n            </div>\n        </div>\n\n        <!-- Issued By -->\n        <div class=\"section\">\n            <h3>Issued By</h3>\n            <div class=\"info-group\">\n                <div class=\"info-row\">\n                    <span>Program Director</span>\n                    <strong>Program Director</strong>\n                </div>\n                <div class=\"info-row\">\n                    <span>Issue Date</span>\n                    <strong>March 18, 2026</strong>\n                </div>\n            </div>\n        </div>\n\n        <!-- Verify -->\n        <div cla